import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useDispatch, useSelector } from 'react-redux';
import { logout } from '../../redux/authSlice';

export default function AdminDashboard() {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const { user } = useSelector(s => s.auth);

  return (
    <div style={{ display:'flex',minHeight:'100vh' }}>
      <aside style={{ width:220,background:'var(--charcoal)',position:'fixed',top:0,bottom:0,left:0,padding:'24px 0' }}>
        <div style={{ padding:'0 20px 20px',borderBottom:'1px solid rgba(255,255,255,.1)',marginBottom:12 }}>
          <div style={{ fontSize:18,color:'#fff',fontFamily:'var(--ff-display)' }}>Admin Panel</div>
          <div style={{ fontSize:11,color:'rgba(255,255,255,.4)',marginTop:2 }}>{user?.email}</div>
        </div>
        {[['📊 Overview','/admin'],['🌸 Products','/admin/products'],['📦 Orders','/admin/orders'],['👥 Users','/admin/users'],['📈 Analytics','/admin/analytics']].map(([l,p]) => (
          <Link key={p} to={p} style={{ display:'block',padding:'10px 20px',color:'rgba(255,255,255,.65)',textDecoration:'none',fontSize:13,fontWeight:500,transition:'all .18s' }}>{l}</Link>
        ))}
        <div style={{ borderTop:'1px solid rgba(255,255,255,.1)',margin:'12px 0' }}/>
        <button onClick={() => { dispatch(logout()); navigate('/'); }} style={{ display:'block',width:'100%',padding:'10px 20px',textAlign:'left',color:'var(--rose)',background:'none',border:'none',cursor:'pointer',fontSize:13,fontWeight:500 }}>🚪 Logout</button>
      </aside>
      <main style={{ flex:1,marginLeft:220,padding:'32px',background:'#F5F5F5',minHeight:'100vh' }}>
        <h1 style={{ fontFamily:'var(--ff-display)',fontSize:32,fontWeight:400,marginBottom:24 }}>Dashboard Overview</h1>
        <div style={{ display:'grid',gridTemplateColumns:'repeat(4,1fr)',gap:20,marginBottom:32 }}>
          {[['💰','Revenue','Connect API'],['📦','Orders','Connect API'],['🌸','Products','Connect API'],['👥','Users','Connect API']].map(([icon,label,val]) => (
            <div key={label} style={{ background:'#fff',borderRadius:16,padding:24,boxShadow:'0 2px 12px rgba(0,0,0,.06)' }}>
              <div style={{ fontSize:30,marginBottom:8 }}>{icon}</div>
              <div style={{ fontSize:10,fontWeight:600,letterSpacing:1,textTransform:'uppercase',color:'var(--warm-gray)',marginBottom:4 }}>{label}</div>
              <div style={{ fontFamily:'var(--ff-display)',fontSize:28,color:'var(--rose-dark)' }}>{val}</div>
            </div>
          ))}
        </div>
        <div style={{ background:'#fff',borderRadius:16,padding:28,boxShadow:'0 2px 12px rgba(0,0,0,.06)' }}>
          <p style={{ color:'var(--warm-gray)',fontSize:14,lineHeight:1.8 }}>
            Connect this admin dashboard to the backend API endpoints:<br/>
            • <code>GET /api/admin/stats</code> — revenue, orders, products, users<br/>
            • <code>GET /api/products</code> — manage products (CRUD)<br/>
            • <code>GET /api/orders</code> — view and update order statuses<br/>
            • <code>GET /api/users</code> — manage customer accounts
          </p>
        </div>
      </main>
    </div>
  );
}
